namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly ModelTrainingService _trainingService;
    private readonly string[] _labelNames;

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        ModelTrainingService trainingService)
    {
        _predictionPool = predictionPool;
        _trainingService = trainingService;

        // Extract label names in correct Score-index order from the trained model
        var mlContext = new MLContext();
        var model = mlContext.Model.Load(_trainingService.GetModelPath(), out _);
        var outputSchema = model.GetOutputSchema(SchemaDefinition.Create(typeof(TicketInput)));
        var labelColumn = outputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetSlotNames(ref slotNames);
        _labelNames = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }

    [HttpPost("classify")]
    public ActionResult<PredictionResponse> Classify([FromBody] PredictionRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _labelNames.Length && i < prediction.Score.Length; i++)
        {
            confidence[_labelNames[i]] = prediction.Score[i];
        }

        return Ok(new PredictionResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            Confidence = confidence
        });
    }

    [HttpPost("train")]
    public ActionResult<EvaluationMetrics> Train()
    {
        var metrics = _trainingService.TrainAndEvaluate();
        return Ok(metrics);
    }
}

